// ─── Add Entry Modal ───
let modalEditId = null;
let modalEditType = null;

function openAddModal(){
  modalEditId = null;
  modalEditType = null;
  el('modalTitle').textContent = 'Add New Entry';
  el('modalType').value = el('resourceTypeSelect').value;
  el('modalIdentifier').value = '';
  el('modalCategory').value = '';
  el('modalGender').value = 'Both';
  el('modalAge').value = 'Both';
  el('modalPriority').value = 'Normal';
  el('modalEnabled').checked = true;
  el('modalPrompt').value = '';
  el('entryModal').classList.add('open');
}

function closeModal(){
  el('entryModal').classList.remove('open');
}

function saveModal(){
  const type  = el('modalType').value;
  const ident = el('modalIdentifier').value.trim();
  const prompt = el('modalPrompt').value.trim();
  if(!ident){ alert('Please enter an Identifier.'); return; }
  if(!prompt){ alert('Please enter the Prompt text.'); return; }

  const entry = {
    id: type + '_new_' + Date.now(),
    identifier: ident,
    gender: el('modalGender').value,
    age: el('modalAge').value,
    category: el('modalCategory').value.trim() || '',
    priority: el('modalPriority').value,
    enabled: el('modalEnabled').checked,
    locked: false,
    prompt: prompt
  };
  if(type === 'originalPrompts'){
    entry.id = 'orig_new_' + Date.now();
    entry.rownum = DATA.originalPrompts.length + 1;
  }

  DATA[type].push(entry);
  if(type === 'originalPrompts') rebuildCatalog();
  saveState();
  refreshCategories();
  rebuildAllDropdowns();
  // Switch resources tab to show new type
  el('resourceTypeSelect').value = type;
  renderResources();
  updateStats();
  closeModal();
}

el('addEntryBtn').addEventListener('click', openAddModal);
el('modalClose').addEventListener('click', closeModal);
el('modalCancel').addEventListener('click', closeModal);
el('modalSave').addEventListener('click', saveModal);
el('entryModal').addEventListener('click', e => { if(e.target===el('entryModal')) closeModal(); });

